lodash_get.code:
function lodashGet(object, path) {
    if (object == null) return null;
    var pathArray;
    if (Array.isArray(path)) {
        pathArray = path;
    } else if (typeof path === "string") {
        var pathStr = path
            .replace(/\["([^"]+)"\]/g, ".$1")
            .replace(/\['([^']+)'\]/g, ".$1")
            .replace(/\[([^\]]+)\]/g, ".$1")
            .replace(/^\./, "");
        pathArray = pathStr.split(".");
        for (var i = 0; i < pathArray.length; i++) {
            if (!isNaN(pathArray[i]) && pathArray[i] !== "") {
                pathArray[i] = Number(pathArray[i]);
            }
        }
    } else { pathArray = []; }
    var result = object;
    for (var j = 0; j < pathArray.length; j++) {
        var key = pathArray[j];
        if (result == null || result[key] === undefined) return null;
        result = result[key];
    }
    return result !== undefined ? result : null;
}

