function buildDetectionCheckboxes(typeMappings, templateName, separator) {
    var sep = separator || '    ';
    var selectedCategory = '';
    if (templateName) {
        for (var category in typeMappings) {
            if (typeMappings[category].indexOf(templateName) > -1) {
                selectedCategory = category; break;
            }
        }
    }
    var result = '';
    var allTypes = Object.keys(typeMappings);
    for (var i = 0; i < allTypes.length; i++) {
        var type = allTypes[i];
        result += type + getCheckBox(type === selectedCategory) + sep;
    }
    return result.trim();
}

// 使用
