function getTableData(form) {
    var origin = form["3159551335743450304"] || [];
    var minRows = 10;
    var count = origin.length < minRows ? minRows : origin.length;
    var result = [];
    for (var i = 0; i < count; i++) {
        var row = origin[i];
        if (row) {
            row["index"] = (i + 1) + '';
        } else {
            row = { index: '', p_col1: '', p_col2: '', p_col3: '' };
        }
        result.push(row);
    }
    return result;
}

