function getStandardIndicator(item) {
    if (item.t_zxyxx) {
        var lower = item.t_zxyxx;
        if (!isNaN(parseFloat(lower)) && !/[\u4e00-\u9fa5]/.test(lower)) lower = '≥' + lower;
        if (item.t_zdyxx) {
            var upper = item.t_zdyxx;
            if (!isNaN(parseFloat(upper)) && !/[\u4e00-\u9fa5]/.test(upper)) upper = '≤' + upper;
            return lower + '-' + upper;
        }
        return lower;
    }
    if (item.t_zdyxx) {
        var upper = item.t_zdyxx;
        if (!isNaN(parseFloat(upper)) && !/[\u4e00-\u9fa5]/.test(upper)) return '≤' + upper;
        return upper;
    }
    return '/';
}

