var tagPrefix = "t_jyjg_";

sample.gaugingTableList.forEach(function(gaugingTable) {
    var arrayKey = Object.keys(gaugingTable).filter(function(k) {
        return k.indexOf(tagPrefix) === 0;
    });

    arrayKey.forEach(function(key) {
        var rows = gaugingTable[key];
        if (!rows || !rows.length) return;

        var titleSuffix = key + "_1";
        var titles = [];
        rows.forEach(function(row) {
            if (row[titleSuffix] && titles.indexOf(row[titleSuffix]) === -1)
                titles.push(row[titleSuffix]);
        });
        var maxCount = titles.length;

        rows.forEach(function(row) {
            var dataValues = [];
            for (var col = 2; col < maxCount + 2; col++) {
                dataValues.push(row[key + "_" + col] || "");
            }
        });
    });
});

